import{_ as a,o as t,c as l,ae as i}from"./chunks/framework.B9lykYDM.js";const c=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"note/我的项目/面试话术.md","filePath":"note/我的项目/面试话术.md"}'),r={name:"note/我的项目/面试话术.md"};function o(n,e,p,u,h,d){return t(),l("div",null,[...e[0]||(e[0]=[i('<h2 id="自我介绍" tabindex="-1">自我介绍 <a class="header-anchor" href="#自我介绍" aria-label="Permalink to &quot;自我介绍&quot;">​</a></h2><p>你好，我叫小寒，毕业于xx理工大学软件工程专业，目前已经有6年的前端开发经验，技术上以 Vue 生态和 TypeScript 为主，对 Vue2、Vue3、工程化、性能优化、SSR、微前端都有比较深入的实践，也有 React、Node.js 的全栈开发经验。我的项目经历既做过直接面向用户PC官网、后台、H5、H5 hybrid、小程序等多端产品，也做过低代码和前端监控等偏平台型和基础设施型的项目。</p><p>在 BT 教育平台这个项目里，我负责过前端整体架构设计、技术管理、CI/CD、发布部署和性能优化，比较有代表性的成果是搭建官网 SSR 体系，把首屏加载时间从 2.1 秒优化到 0.5 秒；同时我也主导了公司级微前端架构搭建，基于 qiankun 在 3 个月内整合了 10 多个不同技术栈的历史项目，解决了样式冲突、路由冲突、状态同步等问题。</p><p>另外我还从 0 到 1 设计过低代码平台，负责 Schema 协议、编排引擎、渲染引擎、变量系统这几块，重点解决复杂嵌套布局下的拖拽放置算法和复杂页面渲染性能问题。我主导搭建了公司的前端全链路监控平台，设计了轻量级监控 SDK 和可视化分析平台，把前端侧从用户访问、页面渲染、用户行为、接口请求、异常上报到告警分析和问题定位这整条链路打通，覆盖了公司 10 多个核心业务，故障发现时效从用户反馈的小时级缩短到了系统告警的分钟级。</p><p>除了项目本身，我也比较关注研发效能和 AI 工具落地，结合 AI 搭建了一套覆盖需求拆解、编码实现、测试验证到 Code Review 的 AI 辅助工作流，显著提升团队整体交付效率。所以我现在更希望加入一个既重视业务结果、也重视技术质量和长期演进的团队，在前端业务开发之外，继续发挥我在架构、稳定性和协同推进方面的价值。</p><h2 id="bt低代码平台" tabindex="-1">BT低代码平台 <a class="header-anchor" href="#bt低代码平台" aria-label="Permalink to &quot;BT低代码平台&quot;">​</a></h2><p>BT低代码平台是一个面向内部运营的自研低代码平台，支持营销活动页和落地页的可视化搭建、发布和版本管理，累计支撑了 300+ 线上页面交付，简单页面交付周期从原来的 2 周 缩短到 2-3 天。</p><p>我在这个项目里担任前端负责人角色，主要负责三块：</p><ul><li>第一块是平台架构设计，采用 Monorepo + 微内核 + 插件化，把 Schema 协议、插件注册机制、渲染上下文、命令系统 这些稳定的平台级通用能力沉淀到内核里，把 物料、属性设置器、数据源适配、调试面板、发布扩展 这些高频变化能力做成插件，保证平台可持续扩展。</li><li>第二块是核心引擎建设，包括 Schema、Renderer、拖拽编排引擎。Schema 不是普通组件树 JSON，而是平台内部的统一协议，结构关系和节点详情分离，方便局部更新、调试和历史回放；Renderer 做成协议驱动的通用执行层，新增物料主要靠注册，不需要频繁改渲染内核；拖拽这块重点解决复杂嵌套布局下的目标容器命中和放置位置判断，采用 射线检测 + 最近父容器回溯，并通过缓存几何信息、requestAnimationFrame 合帧、局部更新和滚动增量修正提升拖拽性能。</li><li>第三块是表达式和调试体系，基于 CodeMirror 6 做变量编辑器，支持补全、错误提示和上下文感知，运行时通过受控上下文和沙箱限制危险能力，同时设计了业务层、实施层、技术层三层调试能力，帮助定位表达式、数据绑定和渲染链路问题。</li></ul><h2 id="前端全链路监控平台" tabindex="-1">前端全链路监控平台 <a class="header-anchor" href="#前端全链路监控平台" aria-label="Permalink to &quot;前端全链路监控平台&quot;">​</a></h2><p>“这个是企业内部的一个前端全链路监控平台，主要解决的是线上问题黑盒、用户报障难复现、排障效率低的问题。我主导设计并落地了公司内部的前端监控 SDK 和可视化分析平台，把前端侧从用户访问、页面渲染、用户行为、接口请求、异常上报到告警分析和问题定位这整条链路打通，覆盖了公司 10 多个核心业务，日均处理百万级日志数据。</p><p>在这个项目里，我主要负责三块：</p><ul><li>第一是从 0 到 1 设计轻量级监控 SDK，采用插件化架构，统一采集 JS 错误、资源异常、接口异常、性能指标和行为轨迹；</li><li>第二是性能和白屏监控，基于 Web Vitals 和 MutationObserver 设计了秒开率、首屏检测、业务关键区域渲染时间等指标；</li><li>第三是可视化分析平台建设，基于 ClickHouse 做海量日志分析，并结合 SourceMap 实现错误源码定位。</li></ul><p>项目落地后，覆盖了 95% 以上核心页面，故障发现时效从用户反馈的小时级缩短到系统告警的分钟级，线上 JS 异常排查效率提升了 60%，同时还基于监控数据持续推动业务优化，比如把网络抖动场景下做题流程异常率从 5% 降到了 0.3%。”</p><h2 id="排查线上问题思路" tabindex="-1">排查线上问题思路 <a class="header-anchor" href="#排查线上问题思路" aria-label="Permalink to &quot;排查线上问题思路&quot;">​</a></h2><p>复现 -&gt; 打点/录制 -&gt; 拆阶段 -&gt; 定位瓶颈 -&gt; 验证优化</p><p>“如果问题集中在‘展开课程目录’，我会先稳定复现这个交互，然后从监控平台确认是这类交互导致 INP 抬高，再到浏览器性能面板录一次交互过程。 定位上我会重点拆三段： 第一，点击后到事件真正开始执行之前，主线程是不是已经被别的任务占满； 第二，展开逻辑本身有没有同步重计算，比如目录树递归处理、复杂 JSON 转换、权限过滤、排序聚合； 第三，状态更新后有没有触发大范围重渲染，比如一次展开导致整棵目录树重新渲染、布局重算或大量 DOM 挂载。 像课程目录这种场景，我会优先怀疑大列表或树组件全量渲染、递归组件层级深、响应式依赖范围过大、展开动画叠加布局计算、以及第三方埋点或播放器脚本在交互时抢占主线程。 如果确认问题存在，我通常会优先尝试按需渲染子节点、做分片渲染或虚拟化、收窄状态更新粒度、把非关键计算移到空闲时机执行。””</p><h2 id="数据是怎么得来的" tabindex="-1">数据是怎么得来的 <a class="header-anchor" href="#数据是怎么得来的" aria-label="Permalink to &quot;数据是怎么得来的&quot;">​</a></h2><p>“这个收益我们不是只看一次前后对比，而是尽量做了统一口径验证。首先，2.1 秒和 0.5 秒都是同一套性能监控口径下统计的同类页面数据，不是随便拿两个时间点对比。其次，SSR 是灰度上线的，我们在灰度阶段对比了新旧链路的 TTFB、首屏时间和服务端 render 耗时，确认提升主要集中在 SSR 相关链路上。再加上缓存命中率提升、实时渲染请求占比下降，这些过程指标也能说明优化确实生效了。因为同期也有接口字段精简和资源优化，所以我们不会说 0.5 秒完全是某一个点带来的，而是这套 SSR 架构优化整体产生的结果。”</p><p>“我们做过灰度对照，不是全量 A/B 实验。灰度阶段同一类页面下，新链路相对于旧链路在 TTFB 和首屏时间上都有明显下降，等稳定后再全量上线。”</p><p>灰度发布：</p><ol><li>用户请求 -&gt; 网关/CDN边缘节点 -&gt; 分流决策层 -&gt; 服务与资源层</li><li>分流决策层：</li></ol><ul><li>观测与执行层：监控系统（错误率/LCP/INP）超过阈值 -&gt; 自动触发回滚</li><li>规则引擎：用户 ID 哈希/地域/白名单</li></ul><ol start="3"><li>服务与资源层：</li></ol><ul><li>存储与配置：灰度规则存储、动态配置中心 -&gt; 新版本 SSR 集群（金丝雀环境）/ 稳定版 SSR 集群</li></ul><p>金丝雀环境是软件部署中的一个形象比喻，来源于历史上的&quot;矿井金丝雀&quot;做法——矿工曾携带金丝雀下井，因为金丝雀对有毒气体极其敏感，一旦金丝雀停止鸣叫或死亡，矿工就立刻撤离，从而避免灾难。 金丝雀环境 = 小规模、真实流量、先于全量上线的新版本运行环境 具体来说，就是将新版本先部署到一小部分真实用户面前，让这部分&quot;金丝雀用户&quot;先体验新版本，通过监控他们的反馈和系统指标，来判断新版本是否稳定，再决定是否逐步扩大范围直至全量上线。</p><h2 id="技术选型" tabindex="-1">技术选型 <a class="header-anchor" href="#技术选型" aria-label="Permalink to &quot;技术选型&quot;">​</a></h2><p>技术价值观：“在做技术选型时，我通常遵循 ‘匹配度优先’和 ‘成本可控’原则。没有银弹，所有的选择都是在特定约束条件下的最优解。对于当时的场景，选择 qiankun 是综合了业务稳定性、团队熟悉度、生态成熟度以及维护成本后的结果。”</p>',28)])])}const S=a(r,[["render",o]]);export{c as __pageData,S as default};
